import React, { useState, useMemo, useCallback } from 'react';
import { Button, DateRangeFilter, addToast } from '@linm-soft/common-components';
import type { DateRangeValue } from '@linm-soft/common-components';
import { useAppDispatch } from '../../../store/hooks';
import { ktService } from '../../../services/kt/ktService';
import type { LedgerEntryDto } from '../../../services/kt/models';
import { createAccountSearchConfig } from '../../../components/search';
import { SearchInput } from '@linm-soft/common-components';
import { reportPageLabels } from '../../../constants/reportPageLabels';
import { getApiErrorMessage } from '../../../utils/getApiErrorMessage';
import erp from '../../../styles/erpPage.module.css';
import { ListSearchRefreshButtons } from '../../../components/list/ListSearchRefreshButtons';
import { LedgerReportGrid } from '../../../components/report';

const labels = reportPageLabels.soCai;
const TEST_ID = 'erp-so-cai';

const SoCaiPage: React.FC = () => {
  const dispatch = useAppDispatch();
  const [accountCode, setAccountCode] = useState('111');
  const [accountName, setAccountName] = useState('');
  const [fromDate, setFromDate] = useState<string | undefined>();
  const [toDate, setToDate] = useState<string | undefined>();
  const [items, setItems] = useState<LedgerEntryDto[]>([]);
  const [loading, setLoading] = useState(false);
  const accountSearchConfig = useMemo(() => createAccountSearchConfig(), []);

  const handleLoad = useCallback(() => {
    if (!accountCode) return;
    setLoading(true);
    ktService.getLedger({ accountCode, fromDate, toDate })
      .then(setItems)
      .catch(err => dispatch(addToast({ message: getApiErrorMessage(err, labels.loadError), type: 'error' })))
      .finally(() => setLoading(false));
  }, [accountCode, fromDate, toDate, dispatch]);

  return (
    <div className={erp.page}>
      <div className={erp.pageHeader}>
        <div className={erp.titleBlock}><h1 className={erp.title}><i className="fas fa-book-open" /> {labels.title}</h1></div>
      </div>
      <div className={erp.filtersBar} data-testid={`${TEST_ID}-filters`}>
        <SearchInput
          config={accountSearchConfig}
          value={accountCode}
          primaryDisplay={accountCode}
          secondaryDisplay={accountName}
          onChange={a => { setAccountCode(a.code); setAccountName(a.name); }}
          onClear={() => { setAccountCode(''); setAccountName(''); }}
          showLabel={false}
          placeholder={labels.accountPlaceholder}
        />
        <DateRangeFilter
          fromDate={fromDate}
          toDate={toDate}
          onChange={(v: DateRangeValue) => { setFromDate(v.fromDate); setToDate(v.toDate); }}
        />
        <Button variant="primary" onClick={handleLoad} loading={loading}>{labels.view}</Button>
        <ListSearchRefreshButtons
          testIdPrefix={TEST_ID}
          onSearch={handleLoad}
          onRefresh={handleLoad}
          showSearch={false}
        />
      </div>
      <div className={erp.tableCard} data-testid={`${TEST_ID}-table-card`}>
        {items.length === 0 ? (
          <div className={erp.empty}>{labels.empty}</div>
        ) : (
          <LedgerReportGrid
            items={items}
            labels={labels}
            testIdPrefix={TEST_ID}
            exportAccountCode={accountCode}
            onRefresh={handleLoad}
          />
        )}
      </div>
    </div>
  );
};

export default SoCaiPage;
